import React from 'react';
import ReactNipple from 'react-nipple';
import 'react-nipple/lib/styles.css';

class Joystick extends React.Component {

  constructor() {
    super()
    this.state = {
      movement: "stopped"
    }
    this.handleMovement = this.handleMovement.bind(this)
    this.handleEnd = this.handleEnd.bind(this)
    this.handleCamera = this.handleCamera.bind(this)
    this.centerCamera = this.centerCamera.bind(this)
  }

  createRequest(direction) {
    const url = "http://" + this.props.address + "/api/" + this.props.controlType + "?direction=" + direction
    return url
  }

  handleMovement(evt, data) {
    if(typeof data.direction !== 'undefined' && typeof data.force !== 'undefined' && typeof data.distance !== 'undefined') {
      if(data.force > 0.65 && data.distance > 20) {
        this.setState (
          function() {
            if(data.direction.angle === 'up') {
              fetch(this.createRequest("forward"))
              return {
                movement: 'forward'
              }
            }
            else if(data.direction.angle === 'down') {
              fetch(this.createRequest("reverse"))
              return {
                movement: 'reverse'
              }
            }
            else if(data.direction.angle === 'left') {
              fetch(this.createRequest("left"))
              return {
                movement: data.direction.angle
              }
            }
            else if(data.direction.angle === 'right') {
              fetch(this.createRequest("right"))
              return {
                movement: data.direction.angle
              }
            }
          }
        )
      }
    }
  }

  handleEnd() {
    fetch(this.createRequest("stop"))
    this.setState (
      function() {
        return {
          movement: "stopped"
        }
      }
    )
  }

  handleCamera(evt, data) {
    if(typeof data.direction !== 'undefined' && typeof data.force !== 'undefined' && typeof data.distance !== 'undefined') {
      fetch(this.createRequest(data.direction.angle))
    }
  }

  centerCamera() {
    fetch(this.createRequest("center"))
  }

  render() {
    const option = {
      mode: 'static',
      position: { top: '50%', left: '50%' }
    }

    const styles = {
      width: 150,
      height: 150,
    }

    if(this.props.controlType === "move") {
      return (
        <div>
          <h4>Movement: {this.state.movement}</h4>
          <ReactNipple className="nippleJoystick" options={option} style={styles}
            onMove={this.handleMovement} onEnd={this.handleEnd} />
        </div>
      )
    }

    else if(this.props.controlType === "camera/pan") {
      return (
        <div>
          <button className="centerButton" onClick={this.centerCamera}>Center</button>
          <ReactNipple className="nippleJoystick" options={option} style={styles}
            onMove={this.handleCamera} />
        </div>
      )
    }

  }
}

export default Joystick
