import React, {Component} from 'react'
import Iframe from 'react-iframe'

class JsmpegPlayer extends Component {

  render() {

    const url = "http://" + this.props.address + "/view-stream.html"

    return (
      <Iframe url={url}
          width="335px"
          height="260px"
          id="cameraStream"
          className="cameraStream"
          display="initial"
          position="relative"/>
    )
  }

}

export default JsmpegPlayer
