import React from 'react'
import JsmpegPlayer from './JsmpegPlayer.js'
import ReactLoading from "react-loading"

class Camera extends React.Component {

  constructor(props) {
    super(props)
    this.state = {
      serverStatus: false,
      url: "http://" + this.props.address + "/api/camera/stream",
      stream: {}
    }
  }

  componentDidMount() {
    fetch(this.state.url + "?cmd=start")
      .then(response => response.json())
      .then(data => {
        this.setState (
          {stream: data}
        )
      })
    setTimeout(() => {  this.setState (
      function() {
        return {
          serverStatus: true
        }
      }
    ) }, 17000)
  }

  componentWillUnmount() {
    fetch(this.state.url +
      "?cmd=stop&ff_pid=" +
      this.state.stream.ff_pid +
      "&wr_pid=" +
      this.state.stream.wr_pid)
  }

  render() {
    const styles = {
      id: "cameraFeed",
      display: "flex",
      flexDirection: "vertical",
      alignItems: "center"
    }

    const loadingStyles = {
      width: 335,
      height: 260,
      display: "flex",
      flexDirection: "column",
      justifyContent: "center",
      alignItems: "center",
      textAlign: "center",
    }

    if(this.state.serverStatus === false) {
       return(
         <div style={loadingStyles}>
           <ReactLoading type={"bars"} color={"white"} />
           <h4><i>Loading Camera...</i></h4>
         </div>
       )
    }

    else if(this.state.serverStatus === true) {
      return(
        <div className="cameraDiv">
          <JsmpegPlayer style={styles} alt="cameraStream" address={this.props.address} />
        </div>
      )
    }
  }
}

export default Camera
