import React from 'react'
import Header from './components/Header'
import MovementControls from './controls/MovementControls'
import CameraControls from './controls/CameraControls'
import Camera from './components/Camera'
//import disableScroll from 'disable-scroll'

class App extends React.Component {
  //disableScroll.on()

  constructor() {
    super()
    this.state = {
      connected: false,
      address: "",
    }
    this.handleChange = this.handleChange.bind(this)
    this.handleSubmit = this.handleSubmit.bind(this)
  }

  handleChange(event) {
   this.setState({address: event.target.value})
  }

  handleSubmit(event) {
   event.preventDefault()
   this.setState(
     function() {
       if(this.state.connected === true) {
         return {
           connected: false
         }
       }
       else if(this.state.connected === false) {
         return {
           connected: true
         }
       }
     }
   )
  }

  render() {

    const submitStyles = {
      marginTop: 15,
      marginBottom: 10,
      backgroundColor: "red",
    }

    if(this.state.connected === false) {
      return (
        <div>
          <Header />
          <div className="mainDiv">
            <form onSubmit={this.handleSubmit}>
              <label>
                Address:
                <input type="text" placeholder="Robot IP Address" value={this.state.address} onChange={this.handleChange} />
              </label>
              <input type="submit" value="Connect" />
            </form>
          </div>
        </div>
      )}

    else if(this.state.connected === true) {
      return (
        <div>
          <div className="mainDiv">
            <form onSubmit={this.handleSubmit}>
              <input type="submit" value="Disconnect" style={submitStyles} />
            </form>
          </div>
          <div className="mainDiv">
            <MovementControls address={this.state.address} controlType="move" />
            <Camera address={this.state.address} controlType="camera/stream" />
            <CameraControls address={this.state.address} controlType="camera/pan" />
          </div>
        </div>
      )}

  }
}

export default App
